/// Merge two sorted arrays into a single sorted array.
/// 
/// # Parameters
/// * `arr1` - A sorted array of integers.
/// * `arr2` - A sorted array of integers.
/// 
/// # Returns
/// A new array that is the sorted combination of `arr1` and `arr2`.
/// 
/// # Example
/// ```rust
/// let arr1 = vec![1, 3, 5];
/// let arr2 = vec![2, 4, 6];
/// let result = merge_sorted_arrays(arr1, arr2);
/// assert_eq!(result, vec![1, 2, 3, 4, 5, 6]);
/// ```
fn merge_sorted_arrays(arr1: Vec<i32>, arr2: Vec<i32>) -> Vec<i32> {
    let mut result = Vec::new();
    let (mut i, mut j) = (0, 0);

    while i < arr1.len() && j < arr2.len() {
        if arr1[i] < arr2[j] {
            result.push(arr1[i]);
            i += 1;
        } else {
            result.push(arr2[j]);
            j += 1;
        }
    }

    result.extend(arr1.iter().skip(i));
    result.extend(arr2.iter().skip(j));
    result
}
