    // Base cases: 0th and 1st Fibonacci numbers
    if (n == 0) {
        return 0;
    } else if (n == 1) {
        return 1;
    }

    // Initialize variables for Fibonacci sequence
    long long a = 0, b = 1, c = 0;

    // Iterate to compute Fibonacci numbers up to n
