// compressString takes a string input and compresses it by counting the consecutive repeats of each character.
// It returns the compressed string or the original string if the compressed string is longer than the original.
// The function includes a comprehensive multi-line comment at the top to describe its behavior, purpose, and parameters.
func compressString(input string) string {
	var result string
	var prev rune
	var count int

	for i := 0; i < len(input); i++ {
		if i == 0 {
			prev = rune(input[i])
			count = 1
		} else {
			if input[i] == prev {
				count++
			} else {
				result += fmt.Sprintf("%c%d", prev, count)
				prev = rune(input[i])
				count = 1
			}
		}
	}

	// Check if compressed string is longer than original
	if len(result) > len(input) {
		return input
	}

	return result
}

