/// Computes the mean, median, and mode of a given list of integers.
///
/// # Parameters
/// * `numbers` - A slice of integers.
///
/// # Returns
/// A `Statistics` struct containing the computed statistics.
///
/// # Examples
/// ```rust
/// let numbers = vec![1, 2, 3, 4, 5];
/// let stats = compute_stats(&numbers);
/// println!("Mean: {}", stats.mean);
/// println!("Median: {}", stats.median);
/// println!("Mode: {}", stats.mode);
/// ```
fn compute_stats(numbers: &[i32]) -> Statistics {
    let mut counts = HashMap::new();
    for &num in numbers {
        *counts.entry(num).or_insert(0) += 1;
    }

    let n = numbers.len();
    let mut sorted_numbers = numbers.to_vec();
    sorted_numbers.sort();

    let mean = sorted_numbers.iter().sum::<i32>() as f64 / n as f64;

    let median: f64 = if n % 2 == 0 {
        (sorted_numbers[n / 2 - 1] + sorted_numbers[n / 2]) as f64 / 2.0
    } else {
        sorted_numbers[n / 2] as f64
    };

    let mode: f64 = counts.values().max().unwrap_or(&0.0) as f64;

    Statistics {
        mean,
        median,
        mode,
    }
}
