// SumSlice computes the sum of a slice of integers.
// It returns the sum if it does not overflow, otherwise it returns an error.
func SumSlice(slice []int) (int, error) {
	if len(slice) == 0 {
		return 0, nil
	}

	var sum int
	for _, num := range slice {
		if sum+num > 0xFFFFFFFF {
			return 0, errors.New("integer overflow: sum exceeds maximum value for 32-bit integers")
		}
		sum += num
	}

	return sum, nil
}

