// maxSubarraySum returns the maximum sum of any contiguous subarray using Kadane's Algorithm.
// It handles edge cases: returns 0 for empty arrays and the highest single negative element
// if all elements are negative.
//
// Parameters:
// nums: A slice of integers.
//
// Returns:
// The maximum sum of any contiguous subarray, or 0 if the array is empty,
// or the highest single negative element if all elements are negative.
func maxSubarraySum(nums []int) int {
	if len(nums) == 0 {
		return 0
	}

	maxCurrent, maxGlobal := nums[0], nums[0]

	for i := 1; i < len(nums); i++ {
		maxCurrent = fmt.Max(maxCurrent, nums[i]+maxCurrent)
		maxGlobal = fmt.Max(maxGlobal, maxCurrent)
	}

	return maxGlobal
}

public class RPNEvaluator {
    /**
     * Evaluates a reverse Polish notation (RPN) expression.
     * 
     * @param expression A string representing the RPN expression.
     * @return The result of evaluating the RPN expression.
     * @throws IllegalArgumentException if the expression is malformed.
     * @throws ArithmeticException if division by zero occurs.
     */
    public static int evaluateRPNExpression(String expression) {
        // Note: This is a simplified implementation and does not handle all edge cases.
        // In a real-world scenario, more robust error checking would be needed.
        String[] tokens = expression.split("\\s+");
        Stack<Integer> stack = new Stack<>();

        for (String token : tokens) {
            if (token.equals(")") || token.equals("]") || token.equals(",")) {
                throw new IllegalArgumentException("Malformed expression");
            }
            if (token.matches("\\d+")) {
                stack.push(Integer.parseInt(token));
            } else if (token.equals("+") || token.equals("-") || token.equals("*") || token.equals("/")) {
                if (stack.size() < 2) {
                    throw new IllegalArgumentException("Insufficient operands");
                }
                int b = stack.pop();
                int a = stack.pop();
                switch (token) {
                    case "+":
                        stack.push(a + b);
                        break;
                    case "-":
                        stack.push(a - b);
                        break;
                    case "*":
                        stack.push(a * b);
                        break;
                    case "/":
                        if (b == 0) {
                            throw new ArithmeticException("Division by zero");
                        }
                        stack.push(a / b);
                        break;
                }
            } else {
                throw new IllegalArgumentException("Invalid operator");
            }
        }

        if (stack.size() != 1) {
            throw new IllegalArgumentException("Malformed expression");
        }

        return stack.pop();
    }
}
